        private void RefreshAvailableModules()
        {
            _availableModules.Clear();
            
            // Find all IModuleInstaller implementations
            var assemblies = AppDomain.CurrentDomain.GetAssemblies();
            var installerType = typeof(Modules.IModuleInstaller);
            
            foreach (var assembly in assemblies)
            {
                try
                {
                    var types = assembly.GetTypes()
                        .Where(t => installerType.IsAssignableFrom(t) && 
                                   t.IsClass && 
                                   !t.IsAbstract);
                    
                    foreach (var type in types)
                    {
                        _availableModules.Add(type.Name);
                    }
                }
                catch
                {
                    // Skip assemblies that can't be scanned
                }
            }
            
            _availableModules.Sort();
        }

