        private void CreateModuleClass(string basePath, string ns)
        {
            var dependsOnAttribute = "";
            var dependsOnUsing = "";
            
            if (_selectedDependencies.Count > 0)
            {
                var depTypes = string.Join(", ", _selectedDependencies.Select(d => $"typeof({d})"));
                dependsOnAttribute = $"\n    [ModuleDependsOn({depTypes})]";
                dependsOnUsing = "\nusing Strada.Core.Modules;";
            }

            var content = GenerateFileHeader() + $@"using Strada.Core.DI;
using Strada.Core.Modules;{dependsOnUsing}

namespace {ns}
{{{dependsOnAttribute}
    public sealed class {_moduleName}Module : IModuleInstaller
    {{
        public string Name => ""{_moduleName}"";

        public void Install(IContainerBuilder builder)
        {{{(_createService && _createInterfaces ? $@"
            builder.Register<I{_moduleName}Service, {_moduleName}Service>(Lifetime.Singleton);" : "")}{(_createController ? $@"
            builder.Register<{_moduleName}Controller>(Lifetime.Singleton);" : "")}
        }}

        public void Initialize(IContainer container)
        {{
        }}

        public void Shutdown()
        {{
        }}
    }}
}}
";
            File.WriteAllText($"{basePath}/{_moduleName}Module.cs", content);
        }

        private void CreateAssemblyDefinition(string basePath, string ns)
        {
            var references = new List<string> { "Strada.Core" };
            
            // Add dependency assembly references
            foreach (var dep in _selectedDependencies)
            {
                // Try to find the assembly name for the dependency
                var depAssembly = FindAssemblyForModule(dep);
                if (!string.IsNullOrEmpty(depAssembly) && !references.Contains(depAssembly))
                {
                    references.Add(depAssembly);
                }
            }

            var referencesJson = string.Join(",\n        ", references.Select(r => $"\"{r}\""));
            
            var content = $@"{{
    ""name"": ""{ns}"",
    ""rootNamespace"": ""{ns}"",
    ""references"": [
        {referencesJson}
    ],
    ""includePlatforms"": [],
    ""excludePlatforms"": [],
    ""allowUnsafeCode"": true,
    ""overrideReferences"": false,
    ""precompiledReferences"": [],
    ""autoReferenced"": true,
    ""defineConstraints"": [],
    ""versionDefines"": [],
    ""noEngineReferences"": false
}}";
            File.WriteAllText($"{basePath}/{_moduleName}.asmdef", content);
        }

        private string FindAssemblyForModule(string moduleName)
        {
            // Try to find the assembly containing this module
            var assemblies = AppDomain.CurrentDomain.GetAssemblies();
            var installerType = typeof(Modules.IModuleInstaller);
            
            foreach (var assembly in assemblies)
            {
                try
                {
                    var type = assembly.GetTypes()
                        .FirstOrDefault(t => t.Name == moduleName && 
                                            installerType.IsAssignableFrom(t));
                    
                    if (type != null)
                    {
                        return assembly.GetName().Name;
                    }
                }
                catch
                {
                    // Skip
                }
            }
            
            return null;
        }

